def get_trash_directory():
    """Returns the path to the 'trash' directory."""
    return os.path.join(os.path.expanduser('~'), '.trash')

def is_file_deletable(file_path):
    """Checks if a file can be deleted."""
    try:
        os.remove(file_path)
        return True
    except PermissionError:
        return False

